const items = $input.all();
const groupedData = {};

// Agrupa os registros por CPF e armazena os telefones em uma lista
items.forEach(item => {
    const { CPF, NOME, TELEFONE } = item.json;

    if (!groupedData[CPF]) {
        groupedData[CPF] = { CPF, NOME, TELEFONES: new Set() };
    }

    // Adiciona os telefones em um Set para evitar duplicatas
    groupedData[CPF].TELEFONES.add(TELEFONE);
});

// Converte para o formato de saída esperado
const output = Object.values(groupedData).map(({ CPF, NOME, TELEFONES }) => {
    const result = { CPF, NOME };

    // Converte o Set para Array e garante que tenha 4 telefones, preenchendo com null se necessário
    const telefoneArray = Array.from(TELEFONES);
    while (telefoneArray.length < 4) {
        telefoneArray.push(null);
    }

    // Adiciona os telefones como TELEFONE 1, TELEFONE 2, ..., TELEFONE 4
    telefoneArray.forEach((tel, index) => {
        result[`TELEFONE ${index + 1}`] = tel;
    });

    return { json: result };
});

return output;

